import React, {
	useEffect,
	useState,
	memo,
	useRef,
} from "react";


import {_monthNames, getStore, updStore } from "../stores/Utils";

import "./MonthPicker.css";
import { SvgIcon_Cmpt } from ".";
import ObserveEvent from "../hooks/observeEvent";
import UseDelayInput from "../hooks/useDelayInput";


const Svg = SvgIcon_Cmpt();

const DropDwnPickerComponent = ({init, onSelect, list, lbl_empty, direction, background, color, callempty, fetchData }) => {
	
	const [open, setOpen] = useState(false);
	const [show, setShow] = useState(false);
	const [showCO, setShowCO] = useState(false);
	const [txt, settxt] = useState("");
	const cmpRef = useRef("");


	const [searchQr, setSearchQ] = useState("");

	let deferredInput = UseDelayInput(searchQr);

	useEffect(() => {
		if (!deferredInput) {
			callempty && callempty()
		} else {
			fetchData(deferredInput);
		}
		return () => {
			//;
		};
	}, [deferredInput]);


	const handleSelection = (v) => {
		onSelect(v)
		handleClick();
	}



	const handleClick = () => {
		if(show){
			setShow(false)
			setShowCO(false)
			setTimeout(() => {
				setOpen(false);
				
			}, 20);
		}else if(!show){
			setOpen(true)
			setTimeout(() => {
				setShow(true)
			}, 50);
			setTimeout(() => {
				setShowCO(true)
			}, 150);
		}
	};

	

	const handleInput = (v) => {
		setSearchQ(v.target.value);
	};

	let labelInit = list.filter(e=>e.id===init)?.[0];

	let dir = direction || "left";

	let _style = {
		"--color-pck":color?color:null,
		"--backColor-pck":background?background:null
	}

	return (
		<div  id={`drpdwn_click_outside`} className={"searchDDBx"} open={open} style={_style} >
			{open?
				<div className={"filter_search_btn _dsplFlx"}>
					 <input
					 	ref={cmpRef}
						type={"text"}
						//aria-autocomplete="both"
						aria-haspopup="false"
						auto-capitalize="off"
						auto-complete="off"
						auto-correct="off"
						spell-check="false"
						placeholder={"search"}
						onChange={handleInput}
					/>
					<div className={"btn_close"} onClick={handleClick}>
						<Svg name={"Xclose"} color={"var(--color-pck)"}/>
					</div>
				</div>
			:
			<div className={"filter_search_btn _dsplFlx"} onClick={handleClick}>
				<div className="lbl date" >
						{lbl_empty}
				</div>
				
					<Svg name={"arrow_drop_down"} color={"var(--color-pck)"}/>
					
			</div>
			}
			
			{open?
			 <div className={"OpenBoxContainer "} style={background?{backgroundColor: background}:null} direction={`${dir}`}>
				<div  className={" monthList"} style={{}}>
					{list.map((elm, wwInd)=>{
						let mnt = elm.label;

						if(!mnt){
							return null;
						}
						return (
							<div key={mnt + "_" +wwInd}  className={"filter_month_item _dsplFlx"} onClick={()=>handleSelection(elm)}>
								<div className="lbl tr_bar_10" >
								
								</div>
								<div className="lbl tr_bar_70" >
									{mnt}
								</div>
								<div className="lbl tr_bar_20" >
									<div>
										<Svg name={init===elm.id?"success":null} color={"var(--color-pck)"}/>
									</div>
								</div>
							</div>
						)
					})}
				</div>
			</div>
			:null}
		
			
		</div>
		
	);
};

export default DropDwnPickerComponent;

